CREATE OR REPLACE FUNCTION pg_try_advisory_lock_with_timeout(key bigint)
RETURNS boolean AS $$
DECLARE
    lock_acquired boolean := false;
    old_timeout text;
BEGIN
    -- Save the current lock_timeout setting
    SELECT current_setting('lock_timeout') INTO old_timeout;

    -- Set lock_timeout to 1 second
    SET LOCAL lock_timeout = '1s';

    BEGIN
        -- Attempt to acquire the advisory lock (will wait up to 1 second)
        PERFORM pg_advisory_xact_lock(key);
        lock_acquired := true;
    EXCEPTION
        WHEN lock_not_available THEN
            lock_acquired := false;
        WHEN deadlock_detected THEN
            lock_acquired := false;
    END;

    -- Restore the original lock_timeout setting
    EXECUTE format('SET LOCAL lock_timeout = %L', old_timeout);

    RETURN lock_acquired;
END;
$$ LANGUAGE plpgsql

