DROP AGGREGATE IF EXISTS GapFill(anyelement);
DROP FUNCTION IF EXISTS GapFillInternal(anyelement, anyelement);

CREATE OR REPLACE FUNCTION GapFillInternal(s anyelement, v anyelement) 
RETURNS anyelement AS $$ 
DECLARE 
    temp alias for $0; 
BEGIN 
    IF v IS NULL AND s IS NOT NULL THEN 
        temp := s; 
    ELSIF s IS NULL AND v IS NOT NULL THEN 
        temp := v; 
    ELSIF s IS NOT NULL AND v IS NOT NULL THEN 
        temp := v; 
    ELSE 
        temp := NULL; 
    END IF;
    RETURN temp;
END; 
$$ LANGUAGE PLPGSQL;

CREATE AGGREGATE GapFill(anyelement) (
    SFUNC = GapFillInternal, 
    STYPE = anyelement
);

