CREATE OR REPLACE FUNCTION fn_concat(p_f_name character varying, p_l_name character varying) 
RETURNS character varying AS $$ 
BEGIN 
    IF p_f_name IS NULL AND p_l_name IS NULL THEN 
        RETURN NULL; 
    ELSEIF p_f_name IS NULL AND p_l_name IS NOT NULL THEN 
        RETURN p_l_name; 
    ELSEIF p_f_name IS NOT NULL AND p_l_name IS NULL THEN 
        RETURN p_f_name; 
    ELSE 
        RETURN CONCAT(p_f_name, ' ', p_l_name); 
    END IF; 
END; 
$$ LANGUAGE plpgsql;

