CREATE OR REPLACE PROCEDURE doWhile()
LANGUAGE plpgsql
AS $$
DECLARE
    v_i INT := 1;
    v_start INT := 120;
    v_counter INT := 1;
    v_end INT := 300;
BEGIN
    WHILE (v_i <= v_end) LOOP
        INSERT INTO table1 (start_val, counter_val, difference, end_val)
            VALUES (v_start, v_counter, v_start + v_counter, v_end);
        v_i := v_i + 1;
        v_counter := v_counter + 1;
    END LOOP;
END;
$$;

CALL doWhile();

CREATE OR REPLACE PROCEDURE insertMore()
LANGUAGE plpgsql
AS $$
DECLARE
    v_start INT;
    v_counter INT := 1;
    v_end INT;
BEGIN
    SELECT COUNT(*) INTO v_end FROM table1;
    SELECT MAX(id) + 1 INTO v_start FROM table1;
    WHILE (v_counter <= v_end) LOOP
        INSERT INTO table1 (start_val, counter_val, difference, end_val)
            VALUES (v_start, v_counter, v_start + v_counter, v_end);
        v_counter := v_counter + 1;
    END LOOP;
END;
$$;

