CREATE OR REPLACE FUNCTION FIND_TEST_TABLE_COLUMN(
    IN_COLUMN1 VARCHAR,
    IN_COLUMN2 VARCHAR,
    IN_COLUMN3 VARCHAR,
    IN_COLUMN4 VARCHAR,
    IN_REQUESTED_COLUMN VARCHAR
) RETURNS VARCHAR AS $$
DECLARE
    C_TEST_TABLE REFCURSOR;
    C_TEST_TABLE_REC RECORD;
    RESULT VARCHAR(255);
    query TEXT;
BEGIN
    query := 'SELECT * FROM test_table WHERE column1 = $1 AND column2 = $2 AND column3 = $3';
    IF IN_COLUMN4 IS NULL THEN
         query := query || ' LIMIT 1';
         OPEN C_TEST_TABLE FOR EXECUTE query USING IN_COLUMN1, IN_COLUMN2, IN_COLUMN3;
    ELSE
         query := query || ' AND column4 = $4 LIMIT 1';
         OPEN C_TEST_TABLE FOR EXECUTE query USING IN_COLUMN1, IN_COLUMN2, IN_COLUMN3, IN_COLUMN4;
    END IF;

    FETCH C_TEST_TABLE INTO C_TEST_TABLE_REC;

    IF FOUND THEN
        IF IN_REQUESTED_COLUMN = 'COLUMN1' THEN
            RESULT := C_TEST_TABLE_REC.column1;
        ELSIF IN_REQUESTED_COLUMN = 'COLUMN2' THEN
            RESULT := C_TEST_TABLE_REC.column2;
        ELSIF IN_REQUESTED_COLUMN = 'COLUMN3' THEN
            RESULT := C_TEST_TABLE_REC.column3;
        END IF;
    END IF;

    CLOSE C_TEST_TABLE;
    RETURN RESULT;
END;
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION enforce_match_results_constraints()
RETURNS TRIGGER AS $$
BEGIN
    -- Condition 1: If rows exist with the same match_id and team_id, the score must match
    IF EXISTS (
        SELECT 1 FROM match_results
        WHERE match_id = NEW.match_id
          AND team_id = NEW.team_id
          AND score IS DISTINCT FROM NEW.score
    ) THEN
        RAISE EXCEPTION 'Score mismatch: rows with match_id=% and team_id=% must have the same score', NEW.match_id, NEW.team_id;
    END IF;

    -- Condition 2: If match_id and team_id combination is unique (no other rows with same match_id and team_id),
    -- then the score must be unique across all other such unique match_id/team_id combinations
    IF NOT EXISTS (
        SELECT 1 FROM match_results
        WHERE match_id = NEW.match_id
          AND team_id = NEW.team_id
    ) THEN
        IF EXISTS (
            SELECT 1 FROM match_results mr
            WHERE mr.score = NEW.score
              AND NOT (mr.match_id = NEW.match_id AND mr.team_id = NEW.team_id)
            GROUP BY mr.match_id, mr.team_id
            HAVING COUNT(*) = 1
        ) THEN
            RAISE EXCEPTION 'Score uniqueness violation: score=% already exists for another unique match_id/team_id combination', NEW.score;
        END IF;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_enforce_match_results_constraints ON match_results;

CREATE TRIGGER trg_enforce_match_results_constraints
BEFORE INSERT OR UPDATE ON match_results
FOR EACH ROW
EXECUTE FUNCTION enforce_match_results_constraints()
